    "slug": "agentic-engineering-jobs",
    "name": "Agentic Engineering Jobs",
    "emoji": "💼",
    "tagline": "Agentic Engineering Jobs — Job board for engineers building agentic systems (L",
    "description": "Agentic Engineering Jobs exposes job board for engineers building agentic systems (LangChain, LlamaIndex, CrewAI) We verified a keyless GET endpoint returning JSON (Jobs). Check the provider docs for rate limits and terms before production use.",
    "category": "social",
